/**통합 게시판 리스트*/
SELECT a.*
,(select count(idx) from t_lecture_board_comment where b_idx = a.idx and status = 1) COMMENT_CNT
,(SELECT USER_MEM_LVL FROM t_user_info WHERE USER_ID = a.REG_ID) USER_MEM_LVL
,@rnum:=@rnum+1 AS R_NUM
FROM
t_lecture_board a,(SELECT @rnum:=0) b
WHERE 1=1 
and board_type = #{boardType}
and edu_seq =#{eduSeq}  
and status ='1'  
order by reg_dtime desc
LIMIT #{firstRecordIndex},#{recordCountPerPage}

/**통합 게시판 리스트 2 삭제대상*/
SELECT a.*,@rnum:=@rnum+1 AS R_NUM
FROM
t_lecture_board a,(SELECT @rnum:=0) b
WHERE 1=1 
and board_type ='eduCommunity' 
and edu_seq =#{eduSeq}  
and status ='1'  
order by idx desc
LIMIT #{firstRecordIndex},#{recordCountPerPage}

	/**게시글 상세조회*/	 
  	SELECT a.* 
  	,(SELECT USER_MEM_LVL FROM t_user_info WHERE USER_ID = a.REG_ID) USER_MEM_LVL
  	FROM t_lecture_board a WHERE a.IDX = #{idx}

