UPDATE t_lecture_board
SET title = #{title}, content = #{content}, mod_id = #{modId}, mod_nm = #{modNm}, mod_dtime = #{modDtime}
,scrty_yn = #{scrtyYn}
WHERE idx = #{idx}

UPDATE t_lecture_board
SET status='0', mod_id = #{1}, mod_nm = #{2}, mod_dtime = DATE_FORMAT(NOW(), '%Y%m%d%H%i')
WHERE idx = #{0}

UPDATE t_lecture_board 
SET hit= hit+1 
WHERE idx = #{0}

update t_lecture_board
set status = #{status}
where idx = #{idx}
